// com/capstone/tryon/python/CatVtonClient.javapackage com.capstone.tryon.python;import com.capstone.tryon.python.dto.PythonInferRequest;import com.capstone.tryon.python.dto.PythonInferResponse;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.beans.factory.annotation.Value;import org.springframework.http.*;import org.springframework.stereotype.Component;import org.springframework.web.client.RestTemplate;@Slf4j@Component@RequiredArgsConstructorpublic class CatVtonClient {    private final RestTemplate restTemplate;    @Value("${AI_SERVER_URL:http://ai-server:8000}")    private String aiServerUrl;    @Value("${USE_MOCK:false}")    private boolean useMock;    public PythonInferResponse infer(PythonInferRequest request) {        if (useMock) {            log.info("[CatVtonClient] MOCK 모드 — 실제 추론 생략");            return mockResponse();        }        String url = aiServerUrl + "/infer";        log.info("[CatVtonClient] POST {} person={} garment={}",                url, request.getPersonImageUrl(), request.getGarmentImageUrl());        HttpHeaders headers = new HttpHeaders();        headers.setContentType(MediaType.APPLICATION_JSON);        ResponseEntity<PythonInferResponse> response = restTemplate.exchange(                url,                HttpMethod.POST,                new HttpEntity<>(request, headers),                PythonInferResponse.class        );        if (response.getBody() == null) {            throw new RuntimeException("Python 서버 응답이 비어있습니다.");        }        return response.getBody();    }    private PythonInferResponse mockResponse() {        PythonInferResponse res = new PythonInferResponse();        // 공개 테스트 이미지 사용 (실제 배포 시 제거)        res.setResultImageUrl("https://picsum.photos/seed/tryon/768/1024");        res.setSuccess(true);        return res;    }}